const body = $input.first().json.body;
const message = body.message || body.edited_message;
if (!message) { return []; }
const chatid = String(message.chat.id);
const fromname = message.from.first_name || 'Sem nome';
const text = message.text || '';
if (!text || text.trim() === '') { return []; }
return [{ json: { chatid, fromname, text } }];

const agora = new Date();
const brasilia = new Date(agora.getTime() - 3 * 60 * 60 * 1000);
const hora = brasilia.getUTCHours();
const dia = brasilia.getUTCDay();
const dentroHorario = dia >= 1 && dia <= 6 && hora >= 8 && hora < 18;
return [{ json: { ...$input.first().json, dentroHorario } }];

const d = $input.first().json;
const texto = 'Ola, ' + d.fromname + '!

A Dra. Vanessa esta fora do horario de atendimento.

Urgencias: procure um veterinario 24 horas.

Demais casos: ela retornara assim que possivel.';
return [{ json: { chatid: d.chatid, texto } }];

const eventos = $input.all();
const ocupada = eventos.length > 0 && !!eventos[0].json.id;
const msg = $('Extrai mensagem').first().json;
return [{ json: { chatid: msg.chatid, fromname: msg.fromname, text: msg.text, ocupada } }];

const estado = $('Avalia Vanessa').first().json;
const rows = $('Busca historico').all();

let historico = [];
try {
  if (rows.length > 0 && rows[0].json.historico) {
    historico = JSON.parse(rows[0].json.historico);
  }
} catch(e) { historico = []; }

historico.push({ role: 'user', content: estado.text });

const situacao = !estado.ocupada ? 'livre' : 'ocupada_novo';

return [{ json: { chatid: estado.chatid, fromname: estado.fromname, text: estado.text, situacao, historico } }];

const d = $input.first().json;
const texto = 'Ola, ' + d.fromname + '!

A Dra. Vanessa esta concluindo um atendimento e retornara em breve.

Fique a vontade para relatar o que esta acontecendo.';
return [{ json: { chatid: d.chatid, texto, historico: d.historico } }];

